@@ -1,88 +0,0 @@
-// This code has been adapted from https://github.com/mysql/mysql-server/blob/ea7087d885006918ad54458e7aad215b1650312c/sql/regexp/regexp_engine.cc
-
-// #cgo macos CFLAGS: -Ibin/darwin-aarch64/include
-// #cgo macos CXXFLAGS: -Ibin/darwin-aarch64/include
-
-#include "unicode/regex.h"
-#include "cstring"
-
-#ifdef __cplusplus
-extern "C" {
-#endif
-
-void appendHead(URegularExpression* m_re, std::u16string& m_replace_buffer, int& m_replace_buffer_pos, UErrorCode* m_error_code, size_t size) {
-	if (size == 0) { return; }
-	int32_t text_length32 = 0;
-	auto text = uregex_getText(m_re, &text_length32, m_error_code);
-	if (*m_error_code != U_ZERO_ERROR) { return; }
-	if (m_replace_buffer.size() < size) { m_replace_buffer.resize(size); }
-	std::copy(text, text + size, &m_replace_buffer.at(0));
-	m_replace_buffer_pos = (int)size;
-}
-
-int tryToAppendReplacement(URegularExpression* m_re, std::u16string& m_replace_buffer, int& m_replace_buffer_pos, UErrorCode* m_error_code, UChar* replacement, int replacementLen) {
-	if (m_replace_buffer.empty()) { return 0; }
-	UChar* ptr = reinterpret_cast<UChar*>(&m_replace_buffer.at(0) + m_replace_buffer_pos);
-	int capacity = m_replace_buffer.size() - m_replace_buffer_pos;
-	return uregex_appendReplacement(m_re, replacement, replacementLen, &ptr, &capacity, m_error_code);
-}
-
-void appendReplacement(URegularExpression* m_re, std::u16string& m_replace_buffer, int& m_replace_buffer_pos, UErrorCode* m_error_code, UChar* replacement, int replacementLen) {
-	int replacement_size = tryToAppendReplacement(m_re, m_replace_buffer, m_replace_buffer_pos, m_error_code, replacement, replacementLen);
-	if (*m_error_code == U_BUFFER_OVERFLOW_ERROR) {
-		size_t required_buffer_size = m_replace_buffer_pos + replacement_size;
-		m_replace_buffer.resize(required_buffer_size);
-		*m_error_code = U_ZERO_ERROR;
-		tryToAppendReplacement(m_re, m_replace_buffer, m_replace_buffer_pos, m_error_code, replacement, replacementLen);
-	}
-	m_replace_buffer_pos += replacement_size;
-}
-
-int tryToAppendTail(URegularExpression* m_re, std::u16string& m_replace_buffer, int& m_replace_buffer_pos, UErrorCode* m_error_code) {
-	if (m_replace_buffer.empty()) { return 0; }
-	UChar* ptr = reinterpret_cast<UChar*>(&m_replace_buffer.at(0) + m_replace_buffer_pos);
-	int capacity = m_replace_buffer.size() - m_replace_buffer_pos;
-	return uregex_appendTail(m_re, &ptr, &capacity, m_error_code);
-}
-
-void appendTail(URegularExpression* m_re, std::u16string& m_replace_buffer, int& m_replace_buffer_pos, UErrorCode* m_error_code) {
-	int tail_size = tryToAppendTail(m_re, m_replace_buffer, m_replace_buffer_pos, m_error_code);
-	if (*m_error_code == U_BUFFER_OVERFLOW_ERROR) {
-		size_t required_buffer_size = m_replace_buffer_pos + tail_size;
-		m_replace_buffer.resize(required_buffer_size);
-		*m_error_code = U_ZERO_ERROR;
-		tryToAppendTail(m_re, m_replace_buffer, m_replace_buffer_pos, m_error_code);
-	}
-	m_replace_buffer_pos += tail_size;
-}
-
-UChar* replace(URegularExpression* regexp, UChar* replacement, int replacementLen, UChar* original, int originalSize, int start, int occurrence, int* returnSize) {
-	*returnSize = originalSize;
-	UErrorCode m_error_code = U_ZERO_ERROR;
-	std::u16string m_replace_buffer;
-	int m_replace_buffer_pos = 0;
-	bool found = uregex_find(regexp, start, &m_error_code);
-	int end_of_previous_match = 0;
-	for (int i = 1; i < occurrence && found; ++i) {
-		end_of_previous_match = uregex_end(regexp, 0, &m_error_code);
-		found = uregex_findNext(regexp, &m_error_code);
-	}
-	if (!found && U_SUCCESS(m_error_code)) { return original; }
-	m_replace_buffer.resize(originalSize);
-	appendHead(regexp, m_replace_buffer, m_replace_buffer_pos, &m_error_code, std::max(end_of_previous_match, start));
-	if (found) {
-		do {
-			appendReplacement(regexp, m_replace_buffer, m_replace_buffer_pos, &m_error_code, replacement, replacementLen);
-		} while (occurrence == 0 && uregex_findNext(regexp, &m_error_code));
-	}
-	appendTail(regexp, m_replace_buffer, m_replace_buffer_pos, &m_error_code);
-	m_replace_buffer.resize(m_replace_buffer_pos);
-	UChar* returnStr = static_cast<UChar*>(malloc(m_replace_buffer.size() * sizeof(UChar*)));
-	memcpy(returnStr, m_replace_buffer.data(), m_replace_buffer.size() * sizeof(UChar*));
-	*returnSize = m_replace_buffer.size();
-	return returnStr;
-}
-
-#ifdef __cplusplus
-} // extern "C"
-#endif

@@ -1,182 +0,0 @@
-package icu
-
-// #cgo CXXFLAGS: -std=c++17
-// #cgo !windows LDFLAGS: -licui18n -licuuc -licudata
-// #cgo icu_static CPPFLAGS: -DU_STATIC_IMPLEMENTATION
-// #cgo windows,icu_static LDFLAGS: -lsicuin -lsicuuc -lsicudt
-// #cgo windows,!icu_static LDFLAGS: -licuin -licuuc -licudt
-// #include "unicode/uregex.h"
-// #include <stdlib.h>
-// #include "file.h"
-import "C"
-
-import (
-	"runtime"
-	"unicode/utf16"
-	"unsafe"
-)
-
-type URegularExpression struct {
-	ptr     *C.URegularExpression
-	cleanup runtime.Cleanup
-}
-
-type UErrorCode C.UErrorCode
-
-func Uregex_open(str *UCharStr, flags uint32, uerr *UErrorCode) *URegularExpression {
-	res := new(URegularExpression)
-	var ec C.UErrorCode
-	res.ptr = C.uregex_open(str.ptr, C.int32_t(str.len), C.uint32_t(flags), nil, &ec)
-	if uerr != nil {
-		*uerr = UErrorCode(ec)
-	}
-	res.cleanup = runtime.AddCleanup(res, func(ptr *C.URegularExpression) {
-		C.uregex_close(ptr)
-	}, res.ptr)
-	return res
-}
-
-func (re *URegularExpression) Free() {
-	re.cleanup.Stop()
-	C.uregex_close(re.ptr)
-}
-
-func Uregex_start(regex *URegularExpression, group int, uerr *UErrorCode) (idx int32) {
-	var ec C.UErrorCode
-	res := C.uregex_start(regex.ptr, C.int32_t(group), &ec)
-	if uerr != nil {
-		*uerr = UErrorCode(ec)
-	}
-	return int32(res)
-}
-
-func Uregex_end(regex *URegularExpression, group int, uerr *UErrorCode) (idx int32) {
-	var ec C.UErrorCode
-	res := C.uregex_end(regex.ptr, C.int32_t(group), &ec)
-	if uerr != nil {
-		*uerr = UErrorCode(ec)
-	}
-	return int32(res)
-}
-
-func Uregex_find(regex *URegularExpression, startIndex int, uerr *UErrorCode) (ok bool) {
-	var ec C.UErrorCode
-	res := C.uregex_find(regex.ptr, C.int32_t(startIndex), &ec)
-	if uerr != nil {
-		*uerr = UErrorCode(ec)
-	}
-	return res != 0
-}
-
-func Uregex_findNext(regex *URegularExpression, uerr *UErrorCode) (ok bool) {
-	var ec C.UErrorCode
-	res := C.uregex_findNext(regex.ptr, &ec)
-	if uerr != nil {
-		*uerr = UErrorCode(ec)
-	}
-	return res != 0
-}
-
-func Uregex_setText(regex *URegularExpression, str *UCharStr, uerr *UErrorCode) {
-	var ec C.UErrorCode
-	C.uregex_setText(regex.ptr, str.ptr, C.int32_t(str.len), &ec)
-	if uerr != nil {
-		*uerr = UErrorCode(ec)
-	}
-}
-
-func Replace(regex *URegularExpression, replacement string, original *UCharStr, start int, occurrence int) string {
-	var replacementStr UCharStr
-	replacementStr.SetString(replacement)
-	defer replacementStr.Free()
-	var res UCharStr
-	var resLen C.int
-	res.ptr = C.replace(regex.ptr, replacementStr.ptr, C.int(replacementStr.len), original.ptr, C.int(original.len), C.int(start), C.int(occurrence), &resLen)
-	res.len = int(resLen)
-	if res.ptr != original.ptr {
-		// replace will not allocate if there is no match, returning original instead.
-		// we return a non-owning reference here if that is the case, but need to take
-		// ownership of the storage if it is newly allocated for us.
-		res.cap = int(resLen)
-	}
-	defer res.Free()
-	return res.GetString()
-}
-
-// A small wrapper around an allocated blob of memory and a populated *UChar.
-type UCharStr struct {
-	ptr *C.UChar
-	len int
-	// If cap != 0, this UCharStr owns the ptr and is responsible for deallocating it.
-	cap int
-
-	cleanup runtime.Cleanup
-}
-
-func (s *UCharStr) SetString(str string) {
-	uints := utf16.Encode([]rune(str))
-	sz := len(uints) + 1
-	s.alloc(sz)
-	var i int
-	for i = 0; i < len(uints); i++ {
-		*(*C.UChar)(unsafe.Pointer(uintptr(unsafe.Pointer(s.ptr)) + uintptr(i)*C.sizeof_UChar)) = C.UChar(uints[i])
-	}
-	*(*C.UChar)(unsafe.Pointer(uintptr(unsafe.Pointer(s.ptr)) + uintptr(i)*C.sizeof_UChar)) = C.UChar(0)
-	s.len = len(uints)
-}
-
-func (s *UCharStr) GetString() string {
-	codeunits := make([]uint16, s.len)
-	for i := 0; i < s.len; i++ {
-		codeunits[i] = uint16(*(*C.UChar)(unsafe.Pointer(uintptr(unsafe.Pointer(s.ptr)) + uintptr(i)*C.sizeof_UChar)))
-	}
-	return string(utf16.Decode(codeunits))
-}
-
-func (s *UCharStr) GetSubstring(start, end int) string {
-	return s.slice(start, end).GetString()
-}
-
-func (s *UCharStr) alloc(sz int) {
-	if sz < 64 {
-		sz = 64
-	}
-	if sz > s.cap {
-		s.Free()
-		s.cap = NextPow2(sz)
-		s.ptr = (*C.UChar)(C.malloc(C.size_t(s.cap * C.sizeof_UChar)))
-		s.cleanup = runtime.AddCleanup(s, func(ptr *C.UChar) {
-			C.free(unsafe.Pointer(ptr))
-		}, s.ptr)
-	}
-}
-
-func (s *UCharStr) Free() {
-	if s.cap > 0 {
-		s.cleanup.Stop()
-		C.free(unsafe.Pointer(s.ptr))
-		s.cap = 0
-		s.ptr = nil
-		s.len = 0
-	}
-}
-
-func (s *UCharStr) slice(start, end int) *UCharStr {
-	// slice never owns the storage and must not outlive the owning *UCharStr, including a SetString called on it.
-	var res UCharStr
-	res.len = end-start
-	res.ptr = (*C.UChar)(unsafe.Pointer(uintptr(unsafe.Pointer(s.ptr)) + 2 * uintptr(start)))
-	return &res
-}
-
-func NextPow2(i int) int {
-	ui := uint32(i)
-	ui--
-	ui |= ui >> 1
-	ui |= ui >> 2
-	ui |= ui >> 4
-	ui |= ui >> 8
-	ui |= ui >> 16
-	ui++
-	return int(ui)
-}
